# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import io
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
import uuid

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and preprocessing objects
model = None
label_encoder = LabelEncoder()
class_names = []

def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(128, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def preprocess_image(image_path):
    image = Image.open(image_path)
    image = image.convert('RGB')
    image = image.resize((224, 224))
    image_array = np.array(image)
    image_array = image_array / 255.0
    return image_array

def load_csv_data(file_path):
    df = pd.read_csv(file_path)
    return df

def prepare_training_data(df):
    X = []
    y = []
    
    for _, row in df.iterrows():
        image_path = row['image_path']
        label = row['label']
        
        try:
            image = preprocess_image(image_path)
            X.append(image)
            y.append(label)
        except Exception as e:
            print(f"Error processing {image_path}: {e}")
            continue
    
    return np.array(X), np.array(y)

@app.route('/train', methods=['POST'])
def train_model():
    global model, label_encoder, class_names
    
    try:
        # Handle CSV upload
        if 'csv_file' not in request.files:
            return jsonify({"error": "No CSV file provided"}), 400
            
        csv_file = request.files['csv_file']
        if csv_file.filename == '':
            return jsonify({"error": "No file selected"}), 400
            
        if csv_file:
            filename = secure_filename(csv_file.filename)
            csv_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            csv_file.save(csv_path)
            
            # Load CSV data
            df = load_csv_data(csv_path)
            
            # Prepare training data
            X, y = prepare_training_data(df)
            
            # Encode labels
            y_encoded = label_encoder.fit_transform(y)
            num_classes = len(label_encoder.classes_)
            class_names = label_encoder.classes_
            y_categorical = tf.keras.utils.to_categorical(y_encoded, num_classes)
            
            # Split data
            X_train, X_test, y_train, y_test = train_test_split(
                X, y_categorical, test_size=0.2, random_state=42
            )
            
            # Create and train model
            model = create_model(num_classes)
            
            # Train model
            history = model.fit(
                X_train, y_train,
                epochs=10,
                batch_size=32,
                validation_data=(X_test, y_test),
                verbose=1
            )
            
            return jsonify({
                "message": "Model trained successfully",
                "classes": class_names.tolist(),
                "accuracy": float(history.history['accuracy'][-1])
            })
            
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    global model, label_encoder
    
    try:
        if model is None:
            return jsonify({"error": "Model not trained yet"}), 400
            
        if 'image' not in request.files:
            return jsonify({"error": "No image provided"}), 400
            
        image_file = request.files['image']
        if image_file.filename == '':
            return jsonify({"error": "No file selected"}), 400
            
        if image_file:
            # Read image
            image = Image.open(image_file)
            image = image.convert('RGB')
            image = image.resize((224, 224))
            image_array = np.array(image)
            image_array = image_array / 255.0
            image_array = np.expand_dims(image_array, axis=0)
            
            # Make prediction
            predictions = model.predict(image_array)
            predicted_class_idx = np.argmax(predictions[0])
            confidence = predictions[0][predicted_class_idx]
            
            # Convert back to class name
            predicted_class = label_encoder.inverse_transform([predicted_class_idx])[0]
            
            return jsonify({
                "predicted_class": predicted_class,
                "confidence": float(confidence),
                "all_predictions": dict(zip(class_names.tolist(), predictions[0].tolist()))
            })
            
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute_examples():
    global model
    
    try:
        # Handle contribution upload (image + label)
        if 'image' not in request.files or 'label' not in request.form:
            return jsonify({"error": "Image and label required"}), 400
            
        image_file = request.files['image']
        label = request.form['label']
        
        if image_file.filename == '':
            return jsonify({"error": "No file selected"}), 400
            
        if image_file:
            # Save contribution
            filename = f"{uuid.uuid4()}.jpg"
            image_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            image_file.save(image_path)
            
            # Here you would typically save the contribution to a database
            # and retrain the model with new data
            
            return jsonify({
                "message": "Contribution accepted",
                "image_saved": filename,
                "label": label
            })
            
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)